#include <bits/stdc++.h>
using namespace std;

string roundToNearest(string str) {
    int n = str.length();

    // Last digit <= 5, round down
    if(str[n-1] - '0' <= 5) {
        str[n-1] = '0';
        return str;
    }

    // Last digit > 5, round up
    str[n-1] = '0';
    int carry = 1;

    // Add carry to previous digits
    for(int i = n-2; i >= 0 && carry; i--) {
        int digit = str[i] - '0';
        digit += carry;
        carry = digit / 10;
        str[i] = (digit % 10) + '0';
    }

    // If carry remains, add '1' at start
    if(carry) {
        str = "1" + str;
    }

    return str;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        string s;
        cin >> s;
        cout << roundToNearest(s) << endl;
    }
    return 0;
}

